export const getGetWorkspaceSummaryUrl = (workspaceId: number,
    params?: GetWorkspaceSummaryParams,) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {

    if (value !== undefined) {
      normalizedParams.append(key, value === null ? 'null' : String(value))
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0 ? `/api/workspaces/${workspaceId}/summary?${stringifiedParams}` : `/api/workspaces/${workspaceId}/summary`
}

